import React, { useState } from 'react';
import './Settings.css';

function Settings() {
  const [language, setLanguage] = useState('ar');
  const [theme, setTheme] = useState('light');
  const [notifications, setNotifications] = useState(true);
  const [features, setFeatures] = useState({
    smartInsights: true,
    advancedReports: false,
    autoBackup: true,
  });

  const handleSave = (e) => {
    e.preventDefault();
    alert('تم حفظ الإعدادات (كل شيء تجريبي حتى الآن).');
  };

  const toggleFeature = (key) => {
    setFeatures((prev) => ({ ...prev, [key]: !prev[key] }));
  };

  return (
    <div className="settings-page">
      <h1 className="settings-title">الإعدادات</h1>
      <p className="settings-subtitle">
        تحكم في الإعدادات العامة الخاصة بطريقة عرض ولوحة التحكم في ديوان الأرض.
      </p>

      <div className="settings-card">
       
       


        <div className="settings-section-header">
          <span className="material-symbols-outlined">visibility</span>
          <h2 className="settings-section-title">إعدادات العرض</h2>
        </div>
        <form className="settings-form" onSubmit={handleSave}>
          <div className="settings-row">
            <label>لغة الواجهة</label>
            <select value={language} onChange={(e) => setLanguage(e.target.value)}>
              <option value="ar">العربية</option>
              <option value="en">الإنجليزية</option>
            </select>
          </div>

          <div className="settings-row">
            <label>نمط الألوان</label>
            <div className="settings-radio-group">
              <label>
                <input
                  type="radio"
                  name="theme"
                  value="light"
                  checked={theme === 'light'}
                  onChange={(e) => setTheme(e.target.value)}
                />
                وضع فاتح
              </label>
              <label>
                <input
                  type="radio"
                  name="theme"
                  value="dark"
                  checked={theme === 'dark'}
                  onChange={(e) => setTheme(e.target.value)}
                />
                وضع داكن (قريباً)
              </label>
            </div>
          </div>

          <div className="settings-row inline">
            <label>الإشعارات</label>
            <label className="toggle-label">
              <input
                type="checkbox"
                checked={notifications}
                onChange={(e) => setNotifications(e.target.checked)}
              />
              تفعيل إشعارات تنبيهات المصاريف والري
            </label>
          </div>

          <div className="settings-actions">
            <button type="submit" className="btn-primary">
              حفظ الإعدادات
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default Settings;

