import React, { useEffect, useRef, useState } from 'react';
import { Chart, registerables } from 'chart.js';
import './Reports.css';

Chart.register(...registerables);

function Reports() {
  const barChartRef = useRef(null);
  const doughnutRefs = useRef([]);
  const [activeTab, setActiveTab] = useState('مصاريف');
  const [selectedYear, setSelectedYear] = useState('2024');

  const allSeasons = [
    { name: 'موسم صيف 2024', year: '2024', percentage: 65, total: '120,000 ج.م', collected: '78,000 ج.م', remaining: '42,000 ج.م', color: '#485935' },
    { name: 'موسم شتاء 2024', year: '2024', percentage: 10, total: '140,000 ج.م', collected: '14,000 ج.م', remaining: '126,000 ج.م', color: '#8a9178' },
    { name: 'موسم خريف 2024', year: '2024', percentage: 0, total: '90,000 ج.م', collected: '0 ج.م', remaining: '90,000 ج.م', color: '#CADBB7' },
    { name: 'موسم شتاء 2023', year: '2023', percentage: 100, total: '150,000 ج.م', collected: '150,000 ج.م', remaining: '0 ج.م', color: '#8a9178' },
    { name: 'موسم صيف 2023', year: '2023', percentage: 90, total: '100,000 ج.م', collected: '90,000 ج.م', remaining: '10,000 ج.م', color: '#CADBB7' },
    { name: 'موسم ربيع 2023', year: '2023', percentage: 100, total: '85,000 ج.م', collected: '85,000 ج.م', remaining: '0 ج.م', color: '#485935' },
    { name: 'موسم شتاء 2022', year: '2022', percentage: 100, total: '110,000 ج.م', collected: '110,000 ج.م', remaining: '0 ج.م', color: '#485935' },
    { name: 'موسم صيف 2022', year: '2022', percentage: 85, total: '95,000 ج.م', collected: '80,750 ج.م', remaining: '14,250 ج.م', color: '#8a9178' },
  ];

  const filteredSeasons = selectedYear === 'الكل' 
    ? allSeasons 
    : allSeasons.filter(s => s.year === selectedYear);

  useEffect(() => {
    let barChart;
    const doughnutCharts = [];

    const initCharts = () => {
      // Bar Chart for Index tab
      if (barChartRef.current) {
        const ctx = barChartRef.current.getContext('2d');
        barChart = new Chart(ctx, {
          type: 'bar',
          data: {
            labels: ['يناير', 'فبراير', 'مارس', 'أبريل', 'مايو', 'يونيو'],
            datasets: [
              { label: 'مصاريف تشغيلية', data: [65, 58, 80, 62, 75, 68], backgroundColor: '#485935', borderRadius: 4, barThickness: 15 },
              { label: 'مصاريف إدارية', data: [42, 35, 55, 38, 48, 45], backgroundColor: '#e2e5dc', borderRadius: 4, barThickness: 15 }
            ]
          },
          options: {
            responsive: true, maintainAspectRatio: false,
            plugins: { legend: { display: false } },
            scales: {
              y: { beginAtZero: true, grid: { display: true, drawBorder: false, color: '#f0f0f0' }, ticks: { display: false } },
              x: { grid: { display: false }, ticks: { font: { family: 'Cairo' }, color: '#8a9178' } }
            }
          }
        });
      }

      // Multiple Seasonal Charts
      doughnutRefs.current.forEach((canvas, index) => {
        if (canvas) {
          const ctx = canvas.getContext('2d');
          const season = filteredSeasons[index];
          if (!season) return;
          const chart = new Chart(ctx, {
            type: 'doughnut',
            data: {
              datasets: [{
                data: [season.percentage, Math.max(0, 100 - season.percentage)],
                backgroundColor: [season.color, '#f0f0f0'],
                borderWidth: 0,
                circumference: 270,
                rotation: 225,
                cutout: '85%'
              }]
            },
            options: {
              responsive: true,
              maintainAspectRatio: false,
              plugins: { tooltip: { enabled: false } }
            }
          });
          doughnutCharts.push(chart);
        }
      });
    };

    const timer = setTimeout(initCharts, 200);

    return () => {
      clearTimeout(timer);
      if (barChart) barChart.destroy();
      doughnutCharts.forEach(c => c.destroy());
    };
  }, [activeTab, selectedYear]);

  const stats = [
    { title: 'إجمالي المصاريف', value: '45,000 ج.م', change: '+5.2%', status: 'up', icon: 'payments' },
    { title: 'إجمالي الإيرادات', value: '82,500 ج.م', change: '-2.1%', status: 'down', icon: 'trending_up' },
    { title: 'صافي الربح', value: '37,500 ج.م', change: '+12.8%', status: 'up', icon: 'savings' },
    
  ];

  const [showAllLands, setShowAllLands] = useState(false);

  const landDetails = [
    { name: 'مزرعة النخيل الشرقية', area: '15', totalCost: '18,000 ج.م', unitCost: '1,200 ج.م', status: 'مستقر', type: 'palm' },
    { name: 'حقل الزيتون الشمالي', area: '22', totalCost: '29,700 ج.م', unitCost: '1,350 ج.م', status: 'مرتفع قليلاً', type: 'olive' },
    { name: 'مشاتل الخضروات', area: '5', totalCost: '5,500 ج.م', unitCost: '1,100 ج.م', status: 'مستقر', type: 'veg' },
    { name: 'مزرعة الرمان الغربية', area: '10', totalCost: '12,000 ج.م', unitCost: '1,200 ج.م', status: 'مستقر', type: 'garden' },
    { name: 'قطاع العنب الجنوبي', area: '18', totalCost: '25,200 ج.م', unitCost: '1,400 ج.م', status: 'مرتفع', type: 'nature' },
    { name: 'صوب الفراولة الحديثة', area: '3', totalCost: '4,500 ج.م', unitCost: '1,500 ج.م', status: 'مستقر', type: 'potted_plant' },
  ];

  const visibleLands = showAllLands ? landDetails : landDetails.slice(0, 3);

  const incomeRows = [
    // 2024
    { source: 'شركة النيل للصادرات', date: '2024-06-10', description: 'دفعة مقدمة محصول البلح', amount: '50,000 ج.م', numericAmount: 50000, method: 'تحويل بنكي', year: '2024' },
    { source: 'تاجر جملة - السوق', date: '2024-06-05', description: 'بيع مخلفات نخيل', amount: '5,500 ج.م', numericAmount: 5500, method: 'نقدي', year: '2024' },
    { source: 'مصنع الزيوت الحديث', date: '2024-05-28', description: 'مستحقات توريد زيتون', amount: '22,000 ج.م', numericAmount: 22000, method: 'شيك', year: '2024' },
    { source: 'مشاتل العبور', date: '2024-05-15', description: 'بيع شتلات طماطم', amount: '5,000 ج.م', numericAmount: 5000, method: 'نقدي', year: '2024' },
    // 2023
    { source: 'شركة الوادي للتصدير', date: '2023-09-20', description: 'توريد محصول زيتون', amount: '40,000 ج.م', numericAmount: 40000, method: 'تحويل بنكي', year: '2023' },
    { source: 'تاجر جملة - السوق المركزي', date: '2023-08-15', description: 'بيع تمور مجففة', amount: '32,000 ج.م', numericAmount: 32000, method: 'نقدي', year: '2023' },
    { source: 'مصنع عصائر النخيل', date: '2023-07-05', description: 'دفعة على حساب تعاقد سنوي', amount: '18,500 ج.م', numericAmount: 18500, method: 'شيك', year: '2023' },
    // 2022
    { source: 'شركة الجنوب الزراعية', date: '2022-10-12', description: 'توريد رمان طازج', amount: '27,000 ج.م', numericAmount: 27000, method: 'تحويل بنكي', year: '2022' },
    { source: 'تاجر جملة - سوق العبور', date: '2022-09-01', description: 'بيع عنب طاولات', amount: '21,500 ج.م', numericAmount: 21500, method: 'نقدي', year: '2022' },
    { source: 'مصنع المربى الحديث', date: '2022-08-18', description: 'توريد فواكه مشكلة', amount: '19,000 ج.م', numericAmount: 19000, method: 'شيك', year: '2022' },
  ];

  const filteredIncomeRows = selectedYear === 'الكل'
    ? incomeRows
    : incomeRows.filter(row => row.year === selectedYear);

  const totalIncome = filteredIncomeRows.reduce((sum, row) => sum + (row.numericAmount || 0), 0);

  const renderTabContent = () => {
    switch (activeTab) {
      case 'مصاريف':
        return (
          <div className="reports-main-grid">
            <div className="report-main-card chart-card">
              <div className="card-header">
                <div className="header-info">
                  <h3>توزيع المصاريف الشهرية</h3>
                  <p>مقارنة بين المصاريف التشغيلية والإدارية</p>
                </div>
                <div className="header-badge">آخر 6 أشهر</div>
              </div>
              <div className="bar-chart-container">
                <canvas ref={barChartRef}></canvas>
              </div>
              <div className="chart-legend">
                <div className="legend-item"><span className="dot admin"></span><span>مصاريف إدارية</span></div>
                <div className="legend-item"><span className="dot operational"></span><span>مصاريف تشغيلية</span></div>
              </div>
            </div>

            <div className="reports-sidebar-col">
              <div className="insight-card">
                <div className="insight-header"><span className="material-symbols-outlined">lightbulb</span><h4>رؤية ذكية</h4></div>
                <p>تكلفة الري في مزرعة النخيل زادت بنسبة 15% عما سبق، ننصح بفحص التمديدات.</p>
              </div>
              <div className="export-card">
                <h3>تصدير التقارير</h3>
                <div className="export-buttons">
                  <button className="btn-export-full">PDF</button>
                  <button className="btn-export-outline">Excel</button>
                </div>
              </div>
            </div>
          </div>
        );
      case 'أرباح':
        return (
          <div className="reports-main-grid single-col">
            <div className="seasons-grid">
              {filteredSeasons.map((season, index) => (
                <div className="report-main-card profits-card" key={index}>
                  <h3>{season.name}</h3>
                  <div className="doughnut-container">
                    <canvas ref={el => doughnutRefs.current[index] = el}></canvas>
                    <div className="doughnut-center">
                      <span className="percentage">%{season.percentage}</span>
                      <span className="desc">من الهدف</span>
                    </div>
                  </div>
                  <div className="profits-details">
                    <div className="profit-target"><span>الهدف الموسمي</span><span className="bold">{season.total}</span></div>
                    <div className="progress-bar-thin"><div className="fill" style={{ width: `${season.percentage}%`, background: season.color }}></div></div>
                    <div className="profit-split">
                      <div className="split-item"><span className="dot collected"></span><span>تم تحصيله: <span className="green">{season.collected}</span></span></div>
                      <div className="split-item"><span className="dot remaining"></span><span>متبقي: <span className="red">{season.remaining}</span></span></div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
            
            <div className="report-main-card table-card">
              <h3>توقعات الأرباح القادمة</h3>
              <table className="land-table">
                <thead>
                  <tr>
                    <th>المحصول</th>
                    <th>موعد الحصاد المتوقع</th>
                    <th>الإنتاج المتوقع</th>
                    <th>القيمة التقديرية</th>
                  </tr>
                </thead>
                <tbody>
                  <tr><td>بلح برحي</td><td>أغسطس 2024</td><td>15 طن</td><td>85,000 ج.م</td></tr>
                  <tr><td>زيتون سيوي</td><td>أكتوبر 2024</td><td>8 طن</td><td>45,000 ج.م</td></tr>
                  <tr><td>طماطم شتوي</td><td>ديسمبر 2024</td><td>20 طن</td><td>30,000 ج.م</td></tr>
                </tbody>
              </table>
            </div>
          </div>
        );
      case 'أراضي':
        return (
          <div className="report-main-card table-card full-width">
            <div className="card-header">
              <h3>تفاصيل تكلفة الأراضي</h3>
              <button className="text-btn" onClick={() => setShowAllLands(!showAllLands)}>
                {showAllLands ? 'عرض أقل' : 'مشاهدة الكل'}
              </button>
            </div>
            <table className="land-table">
              <thead>
                <tr>
                  <th>اسم الأرض</th>
                  <th>المساحة (فدان)</th>
                  <th>التكلفة الإجمالية</th>
                  <th>تكلفة الفدان</th>
                  <th>الحالة</th>
                </tr>
              </thead>
              <tbody>
                {visibleLands.map((land, index) => (
                  <tr key={index}>
                    <td className="land-name-cell">
                      <div className="land-icon">
                        <span className="material-symbols-outlined">
                          {land.type === 'palm' ? 'potted_plant' : land.type === 'olive' ? 'nature' : 'yard'}
                        </span>
                      </div>
                      {land.name}
                    </td>
                    <td>{land.area}</td>
                    <td className="bold">{land.totalCost}</td>
                    <td>{land.unitCost}</td>
                    <td><span className={`status-pill ${land.status.includes('مرتفع') ? 'warning' : 'success'}`}>{land.status}</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        );
      case 'إيرادات':
        return (
          <div className="reports-main-grid single-col">
            <div className="report-main-card table-card full-width">
              <div className="card-header">
                <h3>سجل التدفقات النقدية (الإيرادات)</h3>
                <div className="header-badge">
                  إجمالي: {totalIncome.toLocaleString('ar-EG')} ج.م
                </div>
              </div>
              <table className="land-table">
                <thead>
                  <tr>
                    <th>العميل / المصدر</th>
                    <th>التاريخ</th>
                    <th>البيان</th>
                    <th>المبلغ</th>
                    <th>طريقة الدفع</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredIncomeRows.map((row, index) => (
                    <tr key={index}>
                      <td>{row.source}</td>
                      <td>{row.date}</td>
                      <td>{row.description}</td>
                      <td className="bold">{row.amount}</td>
                      <td>{row.method}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div className="report-main-card chart-card full-width">
              <h3>تحليل مصادر الدخل</h3>
              <div className="income-sources-list">
                <div className="income-item" style={{ marginBottom: '20px' }}>
                  <div className="income-info" style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px' }}>
                    <span style={{ fontWeight: '700', color: '#485935' }}>مبيعات محاصيل</span>
                    <span style={{ color: '#8a9178' }}>75%</span>
                  </div>
                  <div className="progress-bar-thin" style={{ height: '10px', background: '#f0f0f0', borderRadius: '5px' }}>
                    <div className="fill" style={{ width: '75%', background: '#485935', height: '100%', borderRadius: '5px' }}></div>
                  </div>
                </div>
                <div className="income-item" style={{ marginBottom: '20px' }}>
                  <div className="income-info" style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px' }}>
                    <span style={{ fontWeight: '700', color: '#485935' }}>بيع شتلات</span>
                    <span style={{ color: '#8a9178' }}>15%</span>
                  </div>
                  <div className="progress-bar-thin" style={{ height: '10px', background: '#f0f0f0', borderRadius: '5px' }}>
                    <div className="fill" style={{ width: '15%', background: '#8a9178', height: '100%', borderRadius: '5px' }}></div>
                  </div>
                </div>
                <div className="income-item">
                  <div className="income-info" style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px' }}>
                    <span style={{ fontWeight: '700', color: '#485935' }}>خدمات زراعية</span>
                    <span style={{ color: '#8a9178' }}>10%</span>
                  </div>
                  <div className="progress-bar-thin" style={{ height: '10px', background: '#f0f0f0', borderRadius: '5px' }}>
                    <div className="fill" style={{ width: '10%', background: '#CADBB7', height: '100%', borderRadius: '5px' }}></div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="reports-container">
      <div className="reports-header-row">
        <div className="reports-tabs">
          <button className={activeTab === 'أراضي' ? 'active' : ''} onClick={() => setActiveTab('أراضي')}>تكلفة الأرض</button>
          <button className={activeTab === 'أرباح' ? 'active' : ''} onClick={() => setActiveTab('أرباح')}>أرباح الموسم</button>
          <button className={activeTab === 'إيرادات' ? 'active' : ''} onClick={() => setActiveTab('إيرادات')}>تقرير الإيرادات</button>
          <button className={activeTab === 'مصاريف' ? 'active' : ''} onClick={() => setActiveTab('مصاريف')}>تقرير المصاريف</button>
        </div>

        <div className="reports-filters">
          <div className="filter-group">
            <span className="material-symbols-outlined">calendar_today</span>
            <div className="filter-select-wrapper">
              <span className="filter-label">فلترة حسب موسم السنة</span>
              <select
                value={selectedYear}
                onChange={(e) => setSelectedYear(e.target.value)}
                className="filter-select"
              >
                <option value="2024">موسم 2024</option>
                <option value="2023">موسم 2023</option>
                <option value="2022">موسم 2022</option>
                <option value="الكل">كل المواسم</option>
              </select>
            </div>
          </div>
        </div>
      </div>

      <div className="reports-stats-grid">
        {stats.map((stat, index) => (
          <div className="report-stat-card" key={index}>
            <div className="stat-icon-wrapper"><span className="material-symbols-outlined">{stat.icon}</span></div>
            <div className="stat-content">
              <span className="stat-label">{stat.title}</span>
              <div className="stat-value-row">
                <span className="stat-amount">{stat.value}</span>
                <span className={`stat-badge ${stat.status}`}>{stat.change}</span>
              </div>
            </div>
          </div>
        ))}
      </div>

      {renderTabContent()}
    </div>
  );
}

export default Reports;
