import React, { useMemo, useState } from 'react';
import './Irrigation.css';
import '../../components/common/ConfirmDialog.css';
import ConfirmDialog from '../../components/common/ConfirmDialog';

const mockIrrigationSlots = [
  {
    id: 1,
    block: 'قطاع النخيل الشرقي',
    method: 'ري بالتنقيط',
    date: '2024-06-15',
    time: '06:00 ص',
    durationHours: 3,
    status: 'مجدول',
  },
  {
    id: 2,
    block: 'حقل الزيتون الشمالي',
    method: 'ري بالغمر',
    date: '2024-06-15',
    time: '10:00 ص',
    durationHours: 2,
    status: 'مكتمل',
  },
  {
    id: 3,
    block: 'مشاتل الخضار',
    method: 'رش محوري',
    date: '2024-06-16',
    time: '05:30 ص',
    durationHours: 1.5,
    status: 'مجدول',
  },
  {
    id: 4,
    block: 'قطاع العنب الجنوبي',
    method: 'ري بالتنقيط',
    date: '2024-06-16',
    time: '08:00 م',
    durationHours: 2.5,
    status: 'متأخر',
  },
];

function Irrigation() {
  const [slots, setSlots] = useState(mockIrrigationSlots);
  const [statusFilter, setStatusFilter] = useState('الكل');
  const [mode, setMode] = useState('list');
  const [editingSlot, setEditingSlot] = useState(null);
  const [confirmState, setConfirmState] = useState({ open: false, target: null });

  const totalHours = useMemo(
    () => slots.reduce((sum, s) => sum + (s.durationHours || 0), 0),
    [slots]
  );

  const filteredSlots = useMemo(() => {
    return slots.filter((s) =>
      statusFilter === 'الكل' ? true : s.status === statusFilter
    );
  }, [slots, statusFilter]);

  const handleAddSlot = () => {
    setEditingSlot({
      id: null,
      block: '',
      method: 'ري بالتنقيط',
      date: '2024-06-17',
      time: '07:00 ص',
      durationHours: 2,
      status: 'مجدول',
    });
    setMode('form');
  };

  const handleEditSlot = (slot) => {
    setEditingSlot({ ...slot });
    setMode('form');
  };

  const handleDeleteSlot = (slot) => {
    setConfirmState({ open: true, target: slot });
  };

  const handleConfirmDelete = () => {
    const target = confirmState.target;
    if (!target) return;
    setSlots(slots.filter((s) => s.id !== target.id));
    setConfirmState({ open: false, target: null });
  };

  const handleCancelDelete = () => {
    setConfirmState({ open: false, target: null });
  };

  const handleFormChange = (field, value) => {
    setEditingSlot((prev) => ({ ...prev, [field]: value }));
  };

  const handleFormSubmit = (e) => {
    e.preventDefault();
    if (!editingSlot) return;
    const isNew = editingSlot.id == null;
    if (isNew) {
      const nextId = slots.length ? Math.max(...slots.map((s) => s.id)) + 1 : 1;
      const toInsert = {
        ...editingSlot,
        id: nextId,
        durationHours: Number(editingSlot.durationHours) || 0,
      };
      setSlots([toInsert, ...slots]);
    } else {
      const updated = slots.map((s) =>
        s.id === editingSlot.id
          ? {
              ...editingSlot,
              durationHours: Number(editingSlot.durationHours) || 0,
            }
          : s
      );
      setSlots(updated);
    }
    setMode('list');
    setEditingSlot(null);
  };

  const handleFormCancel = () => {
    setMode('list');
    setEditingSlot(null);
  };

  return (
    <div className="irrigation-page">
      <div className="irrigation-header">
        <h1 className="irrigation-title">جدولة الري</h1>
        {mode === 'list' && (
          <button className="btn-primary" onClick={handleAddSlot}>
            <span className="material-symbols-outlined">add</span>
            إضافة دورة ري
          </button>
        )}
      </div>
      <p className="irrigation-subtitle">
        ضبط مواعيد الري لكل القطاعات عشان نقلل الهدر ونحافظ على الرطوبة المناسبة.
      </p>

      {mode === 'form' && editingSlot ? (
        <div className="irr-card irr-form-card">
          <h2 className="form-title">
            {editingSlot.id == null ? 'إضافة دورة ري' : 'تعديل دورة ري'}
          </h2>
          <form className="irr-form" onSubmit={handleFormSubmit}>
            <div className="form-row">
              <label>اسم القطاع</label>
              <input
                type="text"
                value={editingSlot.block}
                onChange={(e) => handleFormChange('block', e.target.value)}
                required
              />
            </div>
            <div className="form-row two-cols">
              <div>
                <label>طريقة الري</label>
                <select
                  value={editingSlot.method}
                  onChange={(e) => handleFormChange('method', e.target.value)}
                >
                  <option value="ري بالتنقيط">ري بالتنقيط</option>
                  <option value="ري بالغمر">ري بالغمر</option>
                  <option value="رش محوري">رش محوري</option>
                </select>
              </div>
              <div>
                <label>حالة الدورة</label>
                <select
                  value={editingSlot.status}
                  onChange={(e) => handleFormChange('status', e.target.value)}
                >
                  <option value="مجدول">مجدول</option>
                  <option value="مكتمل">مكتمل</option>
                  <option value="متأخر">متأخر</option>
                </select>
              </div>
            </div>
            <div className="form-row two-cols">
              <div>
                <label>التاريخ</label>
                <input
                  type="date"
                  value={editingSlot.date}
                  onChange={(e) => handleFormChange('date', e.target.value)}
                />
              </div>
              <div>
                <label>الوقت</label>
                <input
                  type="text"
                  value={editingSlot.time}
                  onChange={(e) => handleFormChange('time', e.target.value)}
                />
              </div>
            </div>
            <div className="form-row">
              <label>المدة (ساعة)</label>
              <input
                type="number"
                value={editingSlot.durationHours}
                onChange={(e) =>
                  handleFormChange('durationHours', e.target.value)
                }
                min="0"
                step="0.5"
              />
            </div>
            <div className="form-actions">
              <button
                type="button"
                className="btn-secondary"
                onClick={handleFormCancel}
              >
                إلغاء
              </button>
              <button type="submit" className="btn-primary">
                حفظ
              </button>
            </div>
          </form>
        </div>
      ) : null}

      <div className="irrigation-stats-row">
        <div className="irr-card">
          <span className="stat-label">عدد دورات الري المجدولة</span>
          <span className="stat-value">{slots.length}</span>
        </div>
        <div className="irr-card">
          <span className="stat-label">إجمالي ساعات الري</span>
          <span className="stat-value">
            {totalHours.toLocaleString('ar-EG')} ساعة
          </span>
        </div>
        <div className="irr-card">
          <span className="stat-label">حالة اليوم</span>
          <span className="stat-value">استهلاك مائي ضمن الحدود</span>
        </div>
      </div>

      <div className="irrigation-filters-row">
        <span className="filter-label">حالة الدورة</span>
        <div className="irr-filters">
          <button
            className={`tab-chip ${statusFilter === 'الكل' ? 'active' : ''}`}
            onClick={() => setStatusFilter('الكل')}
          >
            الكل
          </button>
          <button
            className={`tab-chip ${statusFilter === 'مجدول' ? 'active' : ''}`}
            onClick={() => setStatusFilter('مجدول')}
          >
            مجدول
          </button>
          <button
            className={`tab-chip ${statusFilter === 'مكتمل' ? 'active' : ''}`}
            onClick={() => setStatusFilter('مكتمل')}
          >
            مكتمل
          </button>
          <button
            className={`tab-chip ${statusFilter === 'متأخر' ? 'active' : ''}`}
            onClick={() => setStatusFilter('متأخر')}
          >
            متأخر
          </button>
        </div>
      </div>

      <div className="irrigation-table-card irr-card">
        <table className="irrigation-table">
          <thead>
            <tr>
              <th>القطاع</th>
              <th>طريقة الري</th>
              <th>التاريخ</th>
              <th>الوقت</th>
              <th>المدة (ساعة)</th>
              <th>الحالة</th>
              <th>إجراءات</th>
            </tr>
          </thead>
          <tbody>
            {filteredSlots.map((slot) => (
              <tr key={slot.id}>
                <td>{slot.block}</td>
                <td>{slot.method}</td>
                <td>{new Date(slot.date).toLocaleDateString('ar-EG')}</td>
                <td>{slot.time}</td>
                <td>{slot.durationHours}</td>
                <td>
                  <span className={`status-pill ${slot.status}`}>
                    {slot.status}
                  </span>
                </td>
                <td>
                  <div className="irr-row-actions">
                    <button
                      className="icon-btn danger"
                      onClick={() => handleDeleteSlot(slot)}
                    >
                      <span className="material-symbols-outlined">delete</span>
                    </button>
                    <button
                      className="icon-btn"
                      onClick={() => handleEditSlot(slot)}
                    >
                      <span className="material-symbols-outlined">edit</span>
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      <ConfirmDialog
        open={confirmState.open}
        title="تأكيد حذف دورة الري"
        message="هل تريد حذف دورة الري هذه من جدول الري؟ هذه البيانات تجريبية لغرض العرض فقط."
        confirmLabel="حذف"
        cancelLabel="إلغاء"
        onConfirm={handleConfirmDelete}
        onCancel={handleCancelDelete}
      />
    </div>
  );
}

export default Irrigation;
