import React, { useMemo, useState } from 'react';
import './Expenses.css';
import '../../components/common/ConfirmDialog.css';
import ConfirmDialog from '../../components/common/ConfirmDialog';

const mockExpenses = [
  {
    id: 1,
    category: 'عمالة',
    description: 'يوميات عمال الجمع (الموسم الأول)',
    date: '2023-10-01',
    amount: 1500,
  },
  {
    id: 2,
    category: 'كيماويات',
    description: 'شراء سماد عضوي لنخيل',
    date: '2023-10-03',
    amount: 800,
  },
  {
    id: 3,
    category: 'رش',
    description: 'مبيدات حشرية لمكافحة سوسة النخيل',
    date: '2023-10-05',
    amount: 450,
  },
  {
    id: 4,
    category: 'أخرى',
    description: 'تصليح طلمبة المية الأساسية',
    date: '2023-10-07',
    amount: 1200,
  },
  {
    id: 5,
    category: 'عمالة',
    description: 'أجور عمال تنظيف القنوات',
    date: '2023-10-09',
    amount: 600,
  },
  {
    id: 6,
    category: 'وقود',
    description: 'ديزل لمولدات الري',
    date: '2023-10-10',
    amount: 950,
  },
];

function Expenses() {
  const [expenses, setExpenses] = useState(mockExpenses);
  const [mode, setMode] = useState('list'); // 'list' | 'form'
  const [editingExpense, setEditingExpense] = useState(null);
  const [categoryFilter, setCategoryFilter] = useState('الكل');
  const [searchTerm, setSearchTerm] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 4;
  const [confirmState, setConfirmState] = useState({ open: false, target: null });

  const totalAmount = useMemo(
    () => expenses.reduce((sum, e) => sum + (e.amount || 0), 0),
    [expenses]
  );

  const filteredExpenses = useMemo(() => {
    return expenses.filter((e) => {
      const matchesCategory =
        categoryFilter === 'الكل' ? true : e.category === categoryFilter;
      const matchesSearch =
        !searchTerm ||
        e.description.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [expenses, categoryFilter, searchTerm]);

  const totalPages = Math.max(1, Math.ceil(filteredExpenses.length / pageSize));

  const pagedExpenses = useMemo(() => {
    const start = (currentPage - 1) * pageSize;
    return filteredExpenses.slice(start, start + pageSize);
  }, [filteredExpenses, currentPage]);

  const handleAddExpense = () => {
    setEditingExpense({
      id: null,
      category: 'أخرى',
      description: '',
      date: new Date().toISOString().slice(0, 10),
      amount: 0,
    });
    setMode('form');
  };

  const handleEditExpense = (expense) => {
    setEditingExpense({ ...expense });
    setMode('form');
  };

  const handleDeleteExpense = (expense) => {
    setConfirmState({ open: true, target: expense });
  };

  const handleConfirmDelete = () => {
    const target = confirmState.target;
    if (!target) return;
    const next = expenses.filter((e) => e.id !== target.id);
    setExpenses(next);
    const newTotalPages = Math.max(1, Math.ceil(next.length / pageSize));
    if (currentPage > newTotalPages) setCurrentPage(newTotalPages);
    setConfirmState({ open: false, target: null });
  };

  const handleCancelDelete = () => {
    setConfirmState({ open: false, target: null });
  };

  const handleFormChange = (field, value) => {
    setEditingExpense((prev) => ({ ...prev, [field]: value }));
  };

  const handleFormSubmit = (e) => {
    e.preventDefault();
    if (!editingExpense) return;

    const isNew = editingExpense.id == null;
    if (isNew) {
      const nextId = expenses.length ? Math.max(...expenses.map((e) => e.id)) + 1 : 1;
      const toInsert = { ...editingExpense, id: nextId, amount: Number(editingExpense.amount) || 0 };
      setExpenses([toInsert, ...expenses]);
    } else {
      const updated = expenses.map((e) =>
        e.id === editingExpense.id
          ? { ...editingExpense, amount: Number(editingExpense.amount) || 0 }
          : e
      );
      setExpenses(updated);
    }

    setMode('list');
    setEditingExpense(null);
  };

  const handleFormCancel = () => {
    setMode('list');
    setEditingExpense(null);
  };

  return (
    <div className="expenses-page">
      <div className="expenses-header-row">
        <h1 className="expenses-title">إدارة المصاريف</h1>
        {mode === 'list' && (
          <button className="btn-primary" onClick={handleAddExpense}>
            <span className="material-symbols-outlined">add</span>
            إضافة مصروف جديد
          </button>
        )}
      </div>

      <p className="expenses-subtitle">
        متابعة كل الفلوس اللي بتتصرف في المزرعة عشان ضبط الحسابات.
      </p>

      {mode === 'form' && editingExpense ? (
        <div className="exp-card expenses-form-card">
          <h2 className="form-title">
            {editingExpense.id == null ? 'إضافة مصروف' : 'تعديل مصروف'}
          </h2>
          <form className="expenses-form" onSubmit={handleFormSubmit}>
            <div className="form-row">
              <label>الوصف</label>
              <input
                type="text"
                value={editingExpense.description}
                onChange={(e) => handleFormChange('description', e.target.value)}
                required
              />
            </div>
            <div className="form-row">
              <label>الفئة</label>
              <select
                value={editingExpense.category}
                onChange={(e) => handleFormChange('category', e.target.value)}
              >
                <option value="عمالة">عمالة</option>
                <option value="كيماويات">كيماويات</option>
                <option value="رش">رش</option>
                <option value="وقود">وقود</option>
                <option value="أخرى">أخرى</option>
              </select>
            </div>
            <div className="form-row two-cols">
              <div>
                <label>التاريخ</label>
                <input
                  type="date"
                  value={editingExpense.date}
                  onChange={(e) => handleFormChange('date', e.target.value)}
                />
              </div>
              <div>
                <label>المبلغ (ج.م)</label>
                <input
                  type="number"
                  value={editingExpense.amount}
                  onChange={(e) => handleFormChange('amount', e.target.value)}
                  min="0"
                />
              </div>
            </div>
            <div className="form-actions">
              <button type="button" className="btn-secondary" onClick={handleFormCancel}>
                إلغاء
              </button>
              <button type="submit" className="btn-primary">
                حفظ
              </button>
            </div>
          </form>
        </div>
      ) : (
        <>
          <div className="expenses-stats-row">
            <div className="exp-card stat-card">
              <span className="stat-label">إجمالي مصاريف الشهر</span>
              <span className="stat-value">
                {totalAmount.toLocaleString('ar-EG')} ج.م
              </span>
              <span className="stat-note positive">+14% عن الشهر اللي فات</span>
            </div>
            <div className="exp-card stat-card">
              <span className="stat-label">أكثر حاجة صرفنا فيها</span>
              <span className="stat-value">العمالة</span>
              <span className="stat-note">حوالي 45% من إجمالي المصاريف</span>
            </div>
            <div className="exp-card stat-card">
              <span className="stat-label">فواتير لسه مدفعتش</span>
              <span className="stat-value">3 فواتير</span>
              <span className="stat-note">يُفضّل الدفع خلال 5 أيام</span>
            </div>
          </div>

          <div className="expenses-filters-row">
            <div className="expenses-search">
              <span className="material-symbols-outlined">search</span>
              <input
                type="text"
                placeholder="بتدور على إيه؟"
                value={searchTerm}
                onChange={(e) => {
                  setSearchTerm(e.target.value);
                  setCurrentPage(1);
                }}
              />
            </div>
            <div className="expenses-category-tabs">
              <button
                className={`tab-chip ${
                  categoryFilter === 'الكل' ? 'active' : ''
                }`}
                onClick={() => {
                  setCategoryFilter('الكل');
                  setCurrentPage(1);
                }}
              >
                الكل
              </button>
              <button
                className={`tab-chip ${
                  categoryFilter === 'عمالة' ? 'active' : ''
                }`}
                onClick={() => {
                  setCategoryFilter('عمالة');
                  setCurrentPage(1);
                }}
              >
                عمالة
              </button>
              <button
                className={`tab-chip ${
                  categoryFilter === 'كيماويات' ? 'active' : ''
                }`}
                onClick={() => {
                  setCategoryFilter('كيماويات');
                  setCurrentPage(1);
                }}
              >
                كيماويات
              </button>
              <button
                className={`tab-chip ${
                  categoryFilter === 'رش' ? 'active' : ''
                }`}
                onClick={() => {
                  setCategoryFilter('رش');
                  setCurrentPage(1);
                }}
              >
                رش
              </button>
              <button
                className={`tab-chip ${
                  categoryFilter === 'أخرى' ? 'active' : ''
                }`}
                onClick={() => {
                  setCategoryFilter('أخرى');
                  setCurrentPage(1);
                }}
              >
                أخرى
              </button>
            </div>
          </div>

          <div className="expenses-table-card exp-card">
            <table className="expenses-table">
              <thead>
                <tr>
                  <th>الفئة</th>
                  <th>التاريخ</th>
                  <th>الوصف</th>
                  <th>المبلغ</th>
                  <th>أكشن</th>
                </tr>
              </thead>
              <tbody>
                {pagedExpenses.map((exp) => (
                  <tr key={exp.id}>
                    <td>
                      <span className={`category-pill cat-${exp.category}`}>
                        {exp.category}
                      </span>
                    </td>
                    <td>{new Date(exp.date).toLocaleDateString('ar-EG')}</td>
                    <td>{exp.description}</td>
                    <td>{exp.amount.toLocaleString('ar-EG')} ج.م</td>
                    <td>
                      <div className="exp-row-actions">
                        <button
                          className="icon-btn danger"
                          onClick={() => handleDeleteExpense(exp)}
                          title="حذف"
                        >
                          <span className="material-symbols-outlined">delete</span>
                        </button>
                        <button
                          className="icon-btn"
                          onClick={() => handleEditExpense(exp)}
                          title="تعديل"
                        >
                          <span className="material-symbols-outlined">edit</span>
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>

            <div className="expenses-table-footer">
              <span>
                عرض {pagedExpenses.length} من أصل {filteredExpenses.length} مصروف
              </span>
              <div className="pagination">
                <button
                  className={`page-btn ${currentPage === 1 ? 'disabled' : ''}`}
                  onClick={() =>
                    currentPage > 1 && setCurrentPage(currentPage - 1)
                  }
                >
                  {'<'}
                </button>
                {Array.from({ length: totalPages }).map((_, index) => {
                  const page = index + 1;
                  return (
                    <button
                      key={page}
                      className={`page-btn ${
                        currentPage === page ? 'active' : ''
                      }`}
                      onClick={() => setCurrentPage(page)}
                    >
                      {page}
                    </button>
                  );
                })}
                <button
                  className={`page-btn ${
                    currentPage === totalPages ? 'disabled' : ''
                  }`}
                  onClick={() =>
                    currentPage < totalPages && setCurrentPage(currentPage + 1)
                  }
                >
                  {'>'}
                </button>
              </div>
            </div>
          </div>
        </>
      )}

      <ConfirmDialog
        open={confirmState.open}
        title="تأكيد حذف المصروف"
        message="هل أنت متأكد أنك تريد حذف هذا المصروف؟ لن يؤثر ذلك على بياناتك الحقيقية لأنه بيانات تجريبية الآن."
        confirmLabel="حذف"
        cancelLabel="إلغاء"
        onConfirm={handleConfirmDelete}
        onCancel={handleCancelDelete}
      />
    </div>
  );
}

export default Expenses;
