import React, { useMemo, useState } from 'react';
import './SprayCycles.css';
import '../../components/common/ConfirmDialog.css';
import ConfirmDialog from '../../components/common/ConfirmDialog';

const mockCycles = [
  {
    id: 1,
    name: 'دورة رفع النمو - النخيل',
    date: '2023-11-12',
    cropStage: 'مرحلة التزهير',
    material: 'NPK 10-52-10',
    dosePerFeddan: 200,
    unit: 'جم / فدان',
    totalCost: 1250,
    status: 'تمت',
    statusType: 'success',
    targetArea: 'مزرعة النخيل الشرقية',
    notes:
      'يُراعى الخلط جيداً مع ماء الري وعدم تنفيذ الرش وقت الظهيرة. يفضّل المتابعة بعد 3 أيام لملاحظة أي أعراض.',
    installments: [
      { label: 'القسط الأول', value: 200 },
      { label: 'القسط الثاني', value: 200 },
      { label: 'القسط الثالث', value: 200 },
    ],
  },
  {
    id: 2,
    name: 'مبيدات الحشائش - القمح',
    date: '2023-11-05',
    cropStage: 'مرحلة التفريع',
    material: 'عشبي ولامع على الأوراق',
    dosePerFeddan: 150,
    unit: 'مل / فدان',
    totalCost: 840,
    status: 'مجدولة',
    statusType: 'scheduled',
    targetArea: 'حقل القمح الشمالي',
    notes:
      'تنفيذ الرش في الصباح الباكر أو قبل الغروب. يمنع الرش في حالة هبوب رياح قوية أو توقع سقوط أمطار خلال 6 ساعات.',
    installments: [
      { label: 'القسط الأول', value: 280 },
      { label: 'القسط الثاني', value: 280 },
      { label: 'القسط الثالث', value: 280 },
    ],
  },
  {
    id: 3,
    name: 'مكافحة حشرة المن - الزيتون',
    date: '2023-10-28',
    cropStage: 'بداية العقد',
    material: 'مبيد حشري عضوي',
    dosePerFeddan: 100,
    unit: 'مل / فدان',
    totalCost: 450,
    status: 'تمت',
    statusType: 'success',
    targetArea: 'حقل الزيتون الشمالي',
    notes:
      'يُفضّل الفحص قبل الرش لتحديد مستوى الإصابة. يمكن تكرار المعاملة بعد 10 أيام إذا لزم الأمر.',
    installments: [
      { label: 'القسط الأول', value: 150 },
      { label: 'القسط الثاني', value: 150 },
      { label: 'القسط الثالث', value: 150 },
    ],
  },
  {
    id: 4,
    name: 'دورة التسميد الورقي - الخضار',
    date: '2023-10-15',
    cropStage: 'نمو خضري قوي',
    material: 'زيت معدني',
    dosePerFeddan: 80,
    unit: 'مل / فدان',
    totalCost: 320,
    status: 'مسودة',
    statusType: 'draft',
    targetArea: 'مشاتل الخضروات',
    notes:
      'يُستخدم لتحسين كفاءة الامتصاص الورقي للعناصر. تجنّب خلطه مع مركبات نحاسية.',
    installments: [
      { label: 'القسط الأول', value: 160 },
      { label: 'القسط الثاني', value: 160 },
    ],
  },
];

function SprayCycles() {
  const [cycles, setCycles] = useState(mockCycles);
  const [selectedId, setSelectedId] = useState(mockCycles[0]?.id ?? null);
  const [mode, setMode] = useState('list');
  const [editingCycle, setEditingCycle] = useState(null);
  const [confirmState, setConfirmState] = useState({ open: false, target: null });

  const selectedCycle = useMemo(
    () => cycles.find((c) => c.id === selectedId) || cycles[0],
    [cycles, selectedId]
  );

  const monthlyTotal = useMemo(
    () => cycles.reduce((sum, c) => sum + (c.totalCost || 0), 0),
    [cycles]
  );

  const handleAddCycle = () => {
    setEditingCycle({
      id: null,
      name: '',
      date: '2023-12-01',
      cropStage: '',
      material: '',
      dosePerFeddan: 0,
      unit: 'مل / فدان',
      totalCost: 0,
      status: 'مسودة',
      statusType: 'draft',
      targetArea: '',
      notes: '',
      installments: [],
    });
    setMode('form');
  };

  const handleEditCycle = (cycleId) => {
    const cycle = cycles.find((c) => c.id === cycleId);
    if (!cycle) return;
    setEditingCycle({ ...cycle });
    setMode('form');
  };

  const handleDeleteCycle = (cycleId) => {
    const cycle = cycles.find((c) => c.id === cycleId);
    if (!cycle) return;
    setConfirmState({ open: true, target: cycle });
  };

  const handleConfirmDelete = () => {
    const target = confirmState.target;
    if (!target) return;
    const next = cycles.filter((c) => c.id !== target.id);
    setCycles(next);
    if (selectedId === target.id && next.length) {
      setSelectedId(next[0].id);
    }
    setConfirmState({ open: false, target: null });
  };

  const handleCancelDelete = () => {
    setConfirmState({ open: false, target: null });
  };

  const handleFormChange = (field, value) => {
    setEditingCycle((prev) => ({ ...prev, [field]: value }));
  };

  const handleFormSubmit = (e) => {
    e.preventDefault();
    if (!editingCycle) return;
    const isNew = editingCycle.id == null;
    if (isNew) {
      const nextId = cycles.length
        ? Math.max(...cycles.map((c) => c.id)) + 1
        : 1;
      const toInsert = {
        ...editingCycle,
        id: nextId,
        totalCost: Number(editingCycle.totalCost) || 0,
        dosePerFeddan: Number(editingCycle.dosePerFeddan) || 0,
      };
      setCycles([toInsert, ...cycles]);
      setSelectedId(nextId);
    } else {
      const updated = cycles.map((c) =>
        c.id === editingCycle.id
          ? {
            ...editingCycle,
            totalCost: Number(editingCycle.totalCost) || 0,
            dosePerFeddan: Number(editingCycle.dosePerFeddan) || 0,
          }
          : c
      );
      setCycles(updated);
      setSelectedId(editingCycle.id);
    }
    setMode('list');
    setEditingCycle(null);
  };

  const handleFormCancel = () => {
    setMode('list');
    setEditingCycle(null);
  };

  const handleExportPdf = () => {
    alert('تصدير PDF سيتم تفعيله عند ربط النظام بالتقارير.\nحالياً الزر تجريبي فقط.');
  };

  return (
    <div className="spray-cycles-page">
      <div className="spray-cycles-header">
        <div>
          <h1>دورات الرش</h1>
          <p className="spray-cycles-subtitle">
            متابعة دورات الرش للمحاصيل والكيماويات الزراعية
          </p>
        </div>
        {mode === 'list' && (
          <button className="btn-add-cycle" onClick={handleAddCycle}>
            <span className="material-symbols-outlined">add</span>
            إضافة دورة جديدة
          </button>
        )}
      </div>

      <div className="spray-cycles-layout">
        <div className="spray-cycles-list-card">
          <div className="spray-cycles-list-header">
            <span>اسم الدورة</span>
            <span>تاريخ التنفيذ</span>
            <span>المادة المستخدمة</span>
            <span>التكلفة (ج.م)</span>
            <span>الحالة</span>
            <span>إجراءات</span>
          </div>
          <div className="spray-cycles-list-body">
            {cycles.map((cycle) => (
              <button
                key={cycle.id}
                className={`spray-cycle-row${cycle.id === selectedCycle?.id ? ' active' : ''
                  }`}
                onClick={() => setSelectedId(cycle.id)}
              >
                <span className="cycle-name">{cycle.name}</span>
                <span className="cycle-date">
                  {new Date(cycle.date).toLocaleDateString('ar-EG')}
                </span>
                <span className="cycle-material">{cycle.material}</span>
                <span className="cycle-cost">
                  {cycle.totalCost.toLocaleString('ar-EG')}
                </span>
                <span
                  className={`cycle-status-pill ${cycle.statusType || 'draft'}`}
                >
                  {cycle.status}
                </span>
                <span className="cycle-actions">
                  <span
                    className="icon-btn danger"
                    title="حذف"
                    onClick={(e) => {
                      e.stopPropagation();
                      handleDeleteCycle(cycle.id);
                    }}
                  >
                    <span className="material-symbols-outlined">delete</span>
                  </span>
                  <span
                    className="icon-btn"
                    title="تعديل"
                    onClick={(e) => {
                      e.stopPropagation();
                      handleEditCycle(cycle.id);
                    }}
                  >
                    <span className="material-symbols-outlined">edit</span>
                  </span>
                </span>
              </button>
            ))}
          </div>
        </div>

        <div className="spray-cycles-detail-column">
          {selectedCycle && (
            <>
              {mode === 'form' && editingCycle ? (
                <div className="spray-cycle-detail-card">
                  <h2 className="detail-title">
                    {editingCycle.id == null ? 'إضافة دورة رش' : 'تعديل دورة رش'}
                  </h2>
                  <form className="spray-form" onSubmit={handleFormSubmit}>
                    <div className="detail-grid">
                      <div className="detail-item">
                        <span className="detail-label">اسم الدورة</span>
                        <input
                          type="text"
                          value={editingCycle.name}
                          onChange={(e) => handleFormChange('name', e.target.value)}
                          required
                        />
                      </div>
                      <div className="detail-item">
                        <span className="detail-label">تاريخ التنفيذ</span>
                        <input
                          type="date"
                          value={editingCycle.date}
                          onChange={(e) => handleFormChange('date', e.target.value)}
                        />
                      </div>
                      <div className="detail-item">
                        <span className="detail-label">مرحلة المحصول</span>
                        <input
                          type="text"
                          value={editingCycle.cropStage}
                          onChange={(e) =>
                            handleFormChange('cropStage', e.target.value)
                          }
                        />
                      </div>
                      <div className="detail-item">
                        <span className="detail-label">المزرعة / القطاع</span>
                        <input
                          type="text"
                          value={editingCycle.targetArea}
                          onChange={(e) =>
                            handleFormChange('targetArea', e.target.value)
                          }
                        />
                      </div>
                    </div>

                    <div className="detail-material-row">
                      <div>
                        <span className="detail-label">المادة الفعّالة</span>
                        <input
                          type="text"
                          value={editingCycle.material}
                          onChange={(e) =>
                            handleFormChange('material', e.target.value)
                          }
                        />
                      </div>
                      <div>
                        <span className="detail-label">الجرعة لكل فدان</span>
                        <input
                          type="number"
                          value={editingCycle.dosePerFeddan}
                          onChange={(e) =>
                            handleFormChange('dosePerFeddan', e.target.value)
                          }
                        />
                      </div>
                    </div>

                    <div className="detail-item">
                      <span className="detail-label">التكلفة الإجمالية (ج.م)</span>
                      <input
                        type="number"
                        value={editingCycle.totalCost}
                        onChange={(e) =>
                          handleFormChange('totalCost', e.target.value)
                        }
                      />
                    </div>

                    <div className="detail-notes">
                      <span className="detail-label">ملاحظات الدورة</span>
                      <textarea
                        value={editingCycle.notes}
                        onChange={(e) => handleFormChange('notes', e.target.value)}
                      />
                    </div>

                    <div className="detail-actions">
                      <button
                        type="button"
                        className="btn-secondary"
                        onClick={handleFormCancel}
                      >
                        إلغاء
                      </button>
                      <button type="submit" className="btn-add-cycle">
                        حفظ
                      </button>
                    </div>
                  </form>
                </div>
              ) : (
                <div className="spray-cycle-detail-card">
                  <div className="detail-header-row">
                    <div>
                      <span className="detail-label">اسم الدورة الحالية</span>
                      <h2 className="detail-title">{selectedCycle.name}</h2>
                    </div>
                    <span
                      className={`cycle-status-pill large ${selectedCycle.statusType || 'draft'
                        }`}
                    >
                      {selectedCycle.status}
                    </span>
                  </div>

                  <div className="detail-grid">
                    <div className="detail-item">
                      <span className="detail-label">تاريخ التنفيذ</span>
                      <span className="detail-value">
                        {new Date(selectedCycle.date).toLocaleDateString('ar-EG')}
                      </span>
                    </div>
                    <div className="detail-item">
                      <span className="detail-label">مرحلة المحصول</span>
                      <span className="detail-value">
                        {selectedCycle.cropStage}
                      </span>
                    </div>
                    <div className="detail-item">
                      <span className="detail-label">المزرعة / القطاع</span>
                      <span className="detail-value">
                        {selectedCycle.targetArea}
                      </span>
                    </div>
                    <div className="detail-item">
                      <span className="detail-label">التكلفة الإجمالية</span>
                      <span className="detail-value strong">
                        {selectedCycle.totalCost.toLocaleString('ar-EG')} ج.م
                      </span>
                    </div>
                  </div>

                  <div className="detail-divider" />

                  <div className="detail-material-row">
                    <div>
                      <span className="detail-label">المادة الفعّالة</span>
                      <span className="detail-value material">
                        {selectedCycle.material}
                      </span>
                    </div>
                    <div>
                      <span className="detail-label">الجرعة لكل فدان</span>
                      <span className="detail-value">
                        {selectedCycle.dosePerFeddan} {selectedCycle.unit}
                      </span>
                    </div>
                  </div>

                  <div className="detail-notes">
                    <span className="detail-label">ملاحظات الدورة</span>
                    <p>{selectedCycle.notes}</p>
                  </div>

                  <div className="detail-installments">
                    <span className="detail-label">أقساط الشهر (وهمية)</span>
                    <div className="installments-grid">
                      {selectedCycle.installments?.map((inst, index) => (
                        <div key={index} className="installment-item">
                          <span className="installment-label">
                            {inst.label}
                          </span>
                          <span className="installment-value">
                            {inst.value.toLocaleString('ar-EG')} ج.م
                          </span>
                        </div>
                      ))}
                    </div>
                  </div>

                  <div className="detail-actions">
                    <button
                      className="btn-secondary"
                      onClick={() => handleEditCycle(selectedCycle.id)}
                    >
                      تعديل
                    </button>
                    <button className="btn-outline" onClick={handleExportPdf}>
                      تصدير PDF
                    </button>
                  </div>
                </div>
              )}
              <div className="spray-cycles-summary-card">
                <div className="summary-icon">
                  <span className="material-symbols-outlined">payments</span>
                </div>
                <div className="summary-content">
                  <span className="summary-label">إجمالي مصاريف الشهر</span>
                  <span className="summary-value">
                    {monthlyTotal.toLocaleString('ar-EG')} ج.م رش
                  </span>
                  <span className="summary-note">
                    +12% عن نفس الشهر في الموسم السابق (بيانات وهمية للتجربة)
                  </span>
                </div>
              </div>
            </>
          )}
        </div>
      </div>
      <ConfirmDialog
        open={confirmState.open}
        title="تأكيد حذف دورة الرش"
        message="هل أنت متأكد من حذف دورة الرش هذه من الجدول؟ هذه بيانات تجريبية ولن تؤثر على بيانات حقيقية."
        confirmLabel="حذف"
        cancelLabel="إلغاء"
        onConfirm={handleConfirmDelete}
        onCancel={handleCancelDelete}
      />
    </div>
  );
}

export default SprayCycles;
