import React, { useMemo, useState } from 'react';
import './Notifications.css';

const mockNotifications = [
    {
        id: 1,
        title: 'تذكير بصيانة مضخات الري',
        message: 'موعد صيانة المضخات للسير إلى حالة التشغيل المثلى بعد 3 أيام.',
        time: 'قبل 2 ساعة',
        read: false,
    },
    {
        id: 2,
        title: 'انتهاء الكمية من المبيد',
        message: 'المخزون من مبيد الحشائش في المخزن أقل من 10 كيلو.',
        time: 'أمس',
        read: true,
    },
    {
        id: 3,
        title: 'تقرير مصاريف جديد متاح',
        message: 'تم إنشاء تقرير مصاريف الأسبوع الماضي، يمكنك الاطلاع عليه من صفحة التقارير.',
        time: 'قبل 3 أيام',
        read: false,
    },
];

function Notifications() {
    const [notifications, setNotifications] = useState(mockNotifications);

    const unreadCount = useMemo(
        () => notifications.filter((n) => !n.read).length,
        [notifications]
    );

    const markAllRead = () => {
        setNotifications((prev) => prev.map((n) => ({ ...n, read: true })));
    };

    const toggleRead = (id) => {
        setNotifications((prev) =>
            prev.map((n) => (n.id === id ? { ...n, read: !n.read } : n))
        );
    };

    const clearAll = () => {
        setNotifications([]);
    };

    return (
        <div className="notifications-page">
            <div className="notifications-header">
                <div>
                    <h1>الإشعارات</h1>
                    <p className="notifications-subtitle">
                        متابعة التنبيهات المهمة مثل الصيانة، المخزون، وتقارير النظام.
                    </p>
                </div>
            </div>

            <div className="notifications-list">
                <div className="notifications-stats">
                    <span>الإشعارات غير المقروءة</span>
                    <span className="notifications-badge">{unreadCount}</span>
                </div>

                {notifications.length === 0 ? (
                    <div className="notifications-empty">
                        <span className="material-symbols-outlined">notifications_off</span>
                        <p>لا توجد إشعارات حالياً.</p>
                    </div>
                ) : (
                    <ul>
                        {notifications.map((notification) => (
                            <li
                                key={notification.id}
                                className={`notification-item ${notification.read ? 'read' : 'unread'}`}
                                onClick={() => toggleRead(notification.id)}
                            >
                                <div className="notification-main">
                                    <div className="notification-title">
                                        {notification.title}
                                    </div>
                                    <div className="notification-message">
                                        {notification.message}
                                    </div>
                                </div>
                                <div className="notification-meta">
                                    <span className="notification-time">
                                        {notification.time}
                                    </span>
                                    <span className="notification-dot" />
                                </div>
                            </li>
                        ))}
                    </ul>
                )}

                <div className="notifications-footer-actions">
                    <button className="btn-outline" onClick={markAllRead}>
                        تعليم الكل كمقروء
                    </button>
                    <button className="btn-secondary" onClick={clearAll}>
                        مسح الكل
                    </button>
                </div>
            </div>
        </div>
    );
}

export default Notifications;
