import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './Account.css';
import ConfirmDialog from '../../components/common/ConfirmDialog';

function Account() {
    const navigate = useNavigate();
    const [user, setUser] = useState({
        name: 'أحمد محمد',
        email: 'ahmed@example.com',
        phone: '01001234567',
        region: 'المنصورة، الدقهلية',
        accountType: 'owner',
        lastLogin: '14 مارس 2026، 09:30 ص'
    });
    const [showEditForm, setShowEditForm] = useState(false);
    const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
    const [notification, setNotification] = useState(null);

    const getAccountTypeLabel = (type) => {
        switch (type) {
            case 'owner': return 'صاحب أرض';
            case 'partner': return 'تابع لصاحب أرض';
            case 'engineer': return 'مهندس زراعي';
            case 'manager': return 'مسؤول عن أرض';
            default: return 'مالك أرض';
        }
    };

    const handleEdit = () => {
        setShowEditForm(true);
    };

    const handleDelete = () => {
        setShowDeleteConfirm(true);
    };

    const confirmDelete = () => {
        // Logic for deleting account
        setShowDeleteConfirm(false);
        setNotification('تم حذف حسابك بنجاح. شكراً لاستخدامك ديوان الأرض.');
        setTimeout(() => {
            navigate('/');
        }, 3000);
    };

    const handleSaveEdit = (e) => {
        e.preventDefault();
        // Demo: Just show notification without saving
        setShowEditForm(false);
        setNotification('تم حفظ التغييرات بنجاح (ديمو).');
        setTimeout(() => setNotification(null), 3000);
    };

    const handleCancelEdit = () => {
        setShowEditForm(false);
    };

    return (
        <div className="account-page">
            {notification && (
                <div className="notification-banner">
                    {notification}
                </div>
            )}
            <div className="account-card">
                {showEditForm ? (
                    <form onSubmit={handleSaveEdit} className="edit-form">
                        <h2>تعديل الحساب</h2>
                        <div className="form-group">
                            <label>الاسم</label>
                            <div className="input-icon-group">
                                <span className="material-symbols-outlined">person</span>
                                <input type="text" value={user.name} onChange={(e) => setUser({ ...user, name: e.target.value })} />
                            </div>
                        </div>
                        <div className="form-group">
                            <label>البريد الإلكتروني</label>
                            <div className="input-icon-group">
                                <span className="material-symbols-outlined">mail</span>
                                <input type="email" value={user.email} onChange={(e) => setUser({ ...user, email: e.target.value })} />
                            </div>
                        </div>
                        <div className="form-group">
                            <label>رقم الجوال</label>
                            <div className="input-icon-group">
                                <span className="material-symbols-outlined">phone</span>
                                <input type="text" value={user.phone} onChange={(e) => setUser({ ...user, phone: e.target.value })} />
                            </div>
                        </div>
                        <div className="form-group">
                            <label>المنطقة</label>
                            <div className="input-icon-group">
                                <span className="material-symbols-outlined">location_on</span>
                                <input type="text" value={user.region} onChange={(e) => setUser({ ...user, region: e.target.value })} />
                            </div>
                        </div>
                        <div className="form-actions">
                            <button type="submit" className="btn-primary">حفظ</button>
                            <button type="button" onClick={handleCancelEdit} className="btn-secondary">إلغاء</button>
                        </div>
                    </form>
                ) : (
                    <>
                        <div className="account-header">
                            <div className="account-avatar">
                                <span className="material-symbols-outlined">account_circle</span>
                            </div>
                            <div className="account-info">
                                <h2 className="account-name">{user.name}</h2>
                                <p className="account-email">{user.email}</p>
                            </div>
                        </div>

                        <div className="account-details">
                            <h3>تفاصيل الحساب</h3>
                            <div className="details-grid">
                                <div>
                                    <span className="detail-label">رقم الجوال</span>
                                    <span className="detail-value">{user.phone}</span>
                                </div>
                                <div>
                                    <span className="detail-label">المنطقة</span>
                                    <span className="detail-value">{user.region}</span>
                                </div>
                                <div>
                                    <span className="detail-label">نوع الحساب</span>
                                    <span className="detail-value">{getAccountTypeLabel(user.accountType)}</span>
                                </div>
                                <div>
                                    <span className="detail-label">آخر تسجيل دخول</span>
                                    <span className="detail-value">{user.lastLogin}</span>
                                </div>
                            </div>
                        </div>

                        <div className="account-actions">
                            <button className="btn-secondary" type="button" onClick={handleEdit}>
                                تعديل الحساب
                            </button>
                            <button className="btn-danger" type="button" onClick={handleDelete}>
                                حذف الحساب
                            </button>
                        </div>
                    </>
                )}
            </div>

            <ConfirmDialog
                open={showDeleteConfirm}
                title="تأكيد حذف الحساب"
                message="هل أنت متأكد من حذف حسابك؟ هذا الإجراء لا يمكن التراجع عنه."
                confirmLabel="حذف"
                cancelLabel="إلغاء"
                onConfirm={confirmDelete}
                onCancel={() => setShowDeleteConfirm(false)}
            />
        </div>
    );
}

export default Account;
