import React, { useMemo, useState } from 'react';
import './Labor.css';
import '../../components/common/ConfirmDialog.css';
import ConfirmDialog from '../../components/common/ConfirmDialog';

const mockLaborTasks = [
  {
    id: 1,
    workerName: 'محمد عبدالله',
    taskType: 'حصاد',
    taskTag: 'أعمال حصاد',
    date: '2024-05-24',
    amount: 150,
    paymentStatus: 'تم الدفع',
    paymentStatusType: 'paid',
  },
  {
    id: 2,
    workerName: 'علي حسن',
    taskType: 'خدمة أرض',
    taskTag: 'خدمة أرض عامة',
    date: '2024-05-24',
    amount: 120,
    paymentStatus: 'انتظار',
    paymentStatusType: 'pending',
  },
  {
    id: 3,
    workerName: 'سالم محمود',
    taskType: 'تقليم',
    taskTag: 'تقليم / قص أوراق',
    date: '2024-05-23',
    amount: 100,
    paymentStatus: 'تم الدفع',
    paymentStatusType: 'paid',
  },
  {
    id: 4,
    workerName: 'جمعة إبراهيم',
    taskType: 'تحميل ونقل',
    taskTag: 'تحميل ونقل',
    date: '2024-05-23',
    amount: 150,
    paymentStatus: 'متأخر',
    paymentStatusType: 'late',
  },
  {
    id: 5,
    workerName: 'فهد النصري',
    taskType: 'ري ومتابعة',
    taskTag: 'ري ومتابعة',
    date: '2024-05-22',
    amount: 120,
    paymentStatus: 'تم الدفع',
    paymentStatusType: 'paid',
  },
];

function getInitials(name) {
  if (!name) return '';
  const parts = name.trim().split(' ');
  if (parts.length === 1) return parts[0][0] || '';
  return `${parts[0][0]}${parts[parts.length - 1][0]}`;
}

function Labor() {
  const [tasks, setTasks] = useState(mockLaborTasks);
  const [mode, setMode] = useState('list'); // 'list' | 'form'
  const [editingTask, setEditingTask] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [taskFilter, setTaskFilter] = useState('all');
  const [paymentFilter, setPaymentFilter] = useState('all');
  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 4;

  const totalWorkersToday = tasks.length;
  const totalCompletedTasks = 27; // dummy

  const totalAmount = useMemo(
    () => tasks.reduce((sum, t) => sum + (t.amount || 0), 0),
    [tasks]
  );

  const filteredTasks = useMemo(() => {
    return tasks.filter((t) => {
      const matchesSearch =
        !searchTerm ||
        t.workerName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        t.taskType.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesTask =
        taskFilter === 'all' ? true : t.taskType === taskFilter;

      const matchesPayment =
        paymentFilter === 'all'
          ? true
          : t.paymentStatusType === paymentFilter;

      return matchesSearch && matchesTask && matchesPayment;
    });
  }, [tasks, searchTerm, taskFilter, paymentFilter]);

  const totalPages = Math.max(1, Math.ceil(filteredTasks.length / pageSize));

  const pagedTasks = useMemo(() => {
    const start = (currentPage - 1) * pageSize;
    return filteredTasks.slice(start, start + pageSize);
  }, [filteredTasks, currentPage]);

  const [confirmState, setConfirmState] = useState({ open: false, target: null });

  const handleAddWorker = () => {
    setEditingTask({
      id: null,
      workerName: '',
      taskType: 'حصاد',
      taskTag: 'أعمال حصاد',
      date: new Date().toISOString().slice(0, 10),
      amount: 0,
      paymentStatus: 'انتظار',
      paymentStatusType: 'pending',
    });
    setMode('form');
  };

  const handleEditTask = (task) => {
    setEditingTask({ ...task });
    setMode('form');
  };

  const handleDeleteTask = (task) => {
    setConfirmState({ open: true, target: task });
  };

  const handleConfirmDelete = () => {
    const target = confirmState.target;
    if (!target) return;
    const next = tasks.filter((t) => t.id !== target.id);
    setTasks(next);
    const newTotalPages = Math.max(1, Math.ceil(next.length / pageSize));
    if (currentPage > newTotalPages) setCurrentPage(newTotalPages);
    setConfirmState({ open: false, target: null });
  };

  const handleCancelDelete = () => {
    setConfirmState({ open: false, target: null });
  };

  const handleFormChange = (field, value) => {
    setEditingTask((prev) => ({ ...prev, [field]: value }));
  };

  const handleFormSubmit = (e) => {
    e.preventDefault();
    if (!editingTask) return;

    const isNew = editingTask.id == null;
    if (isNew) {
      const nextId = tasks.length ? Math.max(...tasks.map((t) => t.id)) + 1 : 1;
      const toInsert = {
        ...editingTask,
        id: nextId,
        amount: Number(editingTask.amount) || 0,
      };
      setTasks([toInsert, ...tasks]);
    } else {
      const updated = tasks.map((t) =>
        t.id === editingTask.id
          ? { ...editingTask, amount: Number(editingTask.amount) || 0 }
          : t
      );
      setTasks(updated);
    }

    setMode('list');
    setEditingTask(null);
  };

  const handleFormCancel = () => {
    setMode('list');
    setEditingTask(null);
  };

  return (
    <div className="labor-page">
      <div className="labor-header-row">
        <button className="btn-primary large" onClick={handleAddWorker}>
          <span className="material-symbols-outlined">group_add</span>
          إضافة نفر جديد
        </button>
      </div>

      <div className="labor-main-card labor-card">
        {mode === 'form' && editingTask ? (
          <div className="labor-form-card">
            <h2 className="form-title">
              {editingTask.id == null ? 'إضافة عامل / مهمة' : 'تعديل عامل / مهمة'}
            </h2>
            <form className="labor-form" onSubmit={handleFormSubmit}>
              <div className="form-row">
                <label>اسم العامل</label>
                <input
                  type="text"
                  value={editingTask.workerName}
                  onChange={(e) => handleFormChange('workerName', e.target.value)}
                  required
                />
              </div>
              <div className="form-row two-cols">
                <div>
                  <label>نوع المهمة</label>
                  <select
                    value={editingTask.taskType}
                    onChange={(e) => handleFormChange('taskType', e.target.value)}
                  >
                    <option value="حصاد">حصاد</option>
                    <option value="خدمة أرض">خدمة أرض</option>
                    <option value="تقليم">تقليم</option>
                    <option value="تحميل ونقل">تحميل ونقل</option>
                    <option value="ري ومتابعة">ري ومتابعة</option>
                  </select>
                </div>
                <div>
                  <label>الوصف المختصر للمهمة</label>
                  <input
                    type="text"
                    value={editingTask.taskTag}
                    onChange={(e) => handleFormChange('taskTag', e.target.value)}
                  />
                </div>
              </div>
              <div className="form-row two-cols">
                <div>
                  <label>التاريخ</label>
                  <input
                    type="date"
                    value={editingTask.date}
                    onChange={(e) => handleFormChange('date', e.target.value)}
                  />
                </div>
                <div>
                  <label>المبلغ المستحق (ج.م)</label>
                  <input
                    type="number"
                    value={editingTask.amount}
                    onChange={(e) => handleFormChange('amount', e.target.value)}
                    min="0"
                  />
                </div>
              </div>
              <div className="form-row">
                <label>حالة الدفع</label>
                <select
                  value={editingTask.paymentStatusType}
                  onChange={(e) =>
                    handleFormChange('paymentStatusType', e.target.value)
                  }
                >
                  <option value="paid">تم الدفع</option>
                  <option value="pending">انتظار</option>
                  <option value="late">متأخر</option>
                </select>
              </div>
              <div className="form-actions">
                <button
                  type="button"
                  className="btn-secondary"
                  onClick={handleFormCancel}
                >
                  إلغاء
                </button>
                <button type="submit" className="btn-primary">
                  حفظ
                </button>
              </div>
            </form>
          </div>
        ) : null}

        <div className="labor-stats-row">
          <div className="labor-stat-card">
            <span className="stat-label">إجمالي العمال اليوم</span>
            <span className="stat-value">{totalWorkersToday}</span>
          </div>
          <div className="labor-stat-card">
            <span className="stat-label">المهام قيد التنفيذ</span>
            <span className="stat-value">10</span>
          </div>
          <div className="labor-stat-card">
            <span className="stat-label">إجمالي المستحقات</span>
            <span className="stat-value">
              {totalAmount.toLocaleString('ar-EG')} ج.م
            </span>
          </div>
          <div className="labor-stat-card">
            <span className="stat-label">المهام المكتملة</span>
            <span className="stat-value">{totalCompletedTasks}</span>
          </div>
        </div>

        <div className="labor-filters-row">
          <div className="labor-search-inline">
            <span className="filter-label">بحث سريع</span>
            <div className="labor-search-wrapper small">
              <span className="material-symbols-outlined">search</span>
              <input
                type="text"
                placeholder="اسم العامل أو نوع المهمة..."
                value={searchTerm}
                onChange={(e) => {
                  setSearchTerm(e.target.value);
                  setCurrentPage(1);
                }}
              />
            </div>
          </div>

          <div className="labor-filters-chips">
            <span className="filter-label">فلترة حسب نوع المهمة</span>
            <div>
              <button
                className={`filter-chip ${taskFilter === 'all' ? 'active' : ''}`}
                onClick={() => {
                  setTaskFilter('all');
                  setCurrentPage(1);
                }}
              >
                الكل
              </button>
              <button
                className={`filter-chip ${
                  taskFilter === 'حصاد' ? 'active' : ''
                }`}
                onClick={() => {
                  setTaskFilter('حصاد');
                  setCurrentPage(1);
                }}
              >
                أعمال حصاد
              </button>
              <button
                className={`filter-chip ${
                  taskFilter === 'خدمة أرض' ? 'active' : ''
                }`}
                onClick={() => {
                  setTaskFilter('خدمة أرض');
                  setCurrentPage(1);
                }}
              >
                خدمة أرض
              </button>
              <button
                className={`filter-chip ${
                  taskFilter === 'تقليم' ? 'active' : ''
                }`}
                onClick={() => {
                  setTaskFilter('تقليم');
                  setCurrentPage(1);
                }}
              >
                تقليم / قص
              </button>
            </div>
          </div>

          <div className="labor-filters-chips">
            <span className="filter-label">حالة الدفع</span>
            <div>
              <button
                className={`filter-chip ${
                  paymentFilter === 'all' ? 'active' : ''
                }`}
                onClick={() => {
                  setPaymentFilter('all');
                  setCurrentPage(1);
                }}
              >
                الكل
              </button>
              <button
                className={`filter-chip ${
                  paymentFilter === 'paid' ? 'active' : ''
                }`}
                onClick={() => {
                  setPaymentFilter('paid');
                  setCurrentPage(1);
                }}
              >
                تم الدفع
              </button>
              <button
                className={`filter-chip ${
                  paymentFilter === 'pending' ? 'active' : ''
                }`}
                onClick={() => {
                  setPaymentFilter('pending');
                  setCurrentPage(1);
                }}
              >
                انتظار
              </button>
              <button
                className={`filter-chip ${
                  paymentFilter === 'late' ? 'active' : ''
                }`}
                onClick={() => {
                  setPaymentFilter('late');
                  setCurrentPage(1);
                }}
              >
                متأخر
              </button>
            </div>
          </div>
        </div>

        <div className="labor-table-wrapper">
          <table className="labor-table">
            <thead>
              <tr>
                <th>اسم العامل</th>
                <th>نوع المهمة</th>
                <th>التاريخ</th>
                <th>المبلغ المستحق</th>
                <th>حالة الدفع</th>
                <th>الإجراءات</th>
              </tr>
            </thead>
            <tbody>
              {pagedTasks.map((task) => (
                <tr key={task.id}>
                  <td>
                    <div className="worker-cell">
                      <div className="worker-avatar">
                        <span>{getInitials(task.workerName)}</span>
                      </div>
                      <span>{task.workerName}</span>
                    </div>
                  </td>
                  <td>
                    <span className="task-pill">{task.taskTag}</span>
                  </td>
                  <td>{new Date(task.date).toLocaleDateString('ar-EG')}</td>
                  <td>{task.amount.toLocaleString('ar-EG')} ج.م</td>
                  <td>
                    <span
                      className={`payment-status-pill ${task.paymentStatusType}`}
                    >
                      {task.paymentStatus}
                    </span>
                  </td>
                  <td>
                    <div className="labor-row-actions">
                      <button
                        className="icon-btn danger"
                        onClick={() => handleDeleteTask(task)}
                        title="حذف السجل"
                      >
                        <span className="material-symbols-outlined">
                          delete
                        </span>
                      </button>
                      <button
                        className="icon-btn"
                        onClick={() => handleEditTask(task)}
                        title="تعديل السجل"
                      >
                        <span className="material-symbols-outlined">edit</span>
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div className="labor-table-footer">
          <span>عرض {pagedTasks.length} من أصل {tasks.length} عامل</span>
          <div className="pagination">
            <button
              className={`page-btn ${currentPage === 1 ? 'disabled' : ''}`}
              onClick={() => currentPage > 1 && setCurrentPage(currentPage - 1)}
            >
              {'<'}
            </button>
            {Array.from({ length: totalPages }).map((_, index) => {
              const page = index + 1;
              return (
                <button
                  key={page}
                  className={`page-btn ${currentPage === page ? 'active' : ''}`}
                  onClick={() => setCurrentPage(page)}
                >
                  {page}
                </button>
              );
            })}
            <button
              className={`page-btn ${
                currentPage === totalPages ? 'disabled' : ''
              }`}
              onClick={() =>
                currentPage < totalPages && setCurrentPage(currentPage + 1)
              }
            >
              {'>'}
            </button>
          </div>
        </div>

        <div className="labor-tip-card">
          <span className="tip-label">نصيحة اليوم</span>
          <p>
            يُوصى بجدولة عمالة إضافية لهذا الموسم لزيادة كفاءة الحصاد، ومراجعة
            ساعات العمل الإضافية قبل بداية موسم الذروة. (بيانات وهمية للتجربة)
          </p>
        </div>
      </div>
      <ConfirmDialog
        open={confirmState.open}
        title="تأكيد حذف سجل العامل"
        message="هل أنت متأكد أنك تريد حذف هذا السجل من صفحة العمالة؟ البيانات الحالية تجريبية، لكن الحذف لا يمكن التراجع عنه."
        confirmLabel="حذف"
        cancelLabel="إلغاء"
        onConfirm={handleConfirmDelete}
        onCancel={handleCancelDelete}
      />
    </div>
  );
}

export default Labor;
