import React, { useMemo, useState } from 'react';
import './Chemicals.css';
import '../../components/common/ConfirmDialog.css';
import ConfirmDialog from '../../components/common/ConfirmDialog';

const mockChemicalsPurchases = [
  {
    id: 1,
    date: '2024-05-24',
    name: 'حمض نيتريك',
    quantity: '50 وحدة',
    weight: '500 لتر',
    unitPrice: 3050,
    supplier: 'كيماويات دلتا',
  },
  {
    id: 2,
    date: '2024-05-22',
    name: 'نترات أمونيوم',
    quantity: '100 وحدة',
    weight: '2500 كجم',
    unitPrice: 3300,
    supplier: 'شركة الصحراء للأسمدة',
  },
  {
    id: 3,
    date: '2024-05-18',
    name: 'بوتاس فني',
    quantity: '30 وحدة',
    weight: '300 كجم',
    unitPrice: 2875,
    supplier: 'مكتورات التجربة',
  },
  {
    id: 4,
    date: '2024-05-15',
    name: 'هيدروكسيد صوديوم',
    quantity: '30 وحدة',
    weight: '750 كجم',
    unitPrice: 3200,
    supplier: 'كيماويات دلتا',
  },
];

function Chemicals() {
  const [purchases, setPurchases] = useState(mockChemicalsPurchases);
  const [mode, setMode] = useState('list');
  const [editingPurchase, setEditingPurchase] = useState(null);
  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 4;
  const [confirmState, setConfirmState] = useState({ open: false, target: null });

  const totalAmount = useMemo(
    () => purchases.reduce((sum, p) => sum + (p.unitPrice || 0), 0),
    [purchases]
  );

  const totalPages = Math.max(1, Math.ceil(purchases.length / pageSize));

  const pagedPurchases = useMemo(() => {
    const start = (currentPage - 1) * pageSize;
    return purchases.slice(start, start + pageSize);
  }, [purchases, currentPage]);

  const handleAddPurchase = () => {
    setEditingPurchase({
      id: null,
      date: new Date().toISOString().slice(0, 10),
      name: '',
      quantity: '',
      weight: '',
      unitPrice: 0,
      supplier: '',
    });
    setMode('form');
  };

  const handleEditPurchase = (purchase) => {
    setEditingPurchase({ ...purchase });
    setMode('form');
  };

  const handleDeletePurchase = (purchase) => {
    setConfirmState({ open: true, target: purchase });
  };

  const handleConfirmDelete = () => {
    const target = confirmState.target;
    if (!target) return;
    const next = purchases.filter((p) => p.id !== target.id);
    setPurchases(next);
    const newTotalPages = Math.max(1, Math.ceil(next.length / pageSize));
    if (currentPage > newTotalPages) setCurrentPage(newTotalPages);
    setConfirmState({ open: false, target: null });
  };

  const handleCancelDelete = () => {
    setConfirmState({ open: false, target: null });
  };

  const handleFormChange = (field, value) => {
    setEditingPurchase((prev) => ({ ...prev, [field]: value }));
  };

  const handleFormSubmit = (e) => {
    e.preventDefault();
    if (!editingPurchase) return;

    const isNew = editingPurchase.id == null;
    if (isNew) {
      const nextId = purchases.length
        ? Math.max(...purchases.map((p) => p.id)) + 1
        : 1;
      const toInsert = {
        ...editingPurchase,
        id: nextId,
        unitPrice: Number(editingPurchase.unitPrice) || 0,
      };
      setPurchases([toInsert, ...purchases]);
    } else {
      const updated = purchases.map((p) =>
        p.id === editingPurchase.id
          ? {
              ...editingPurchase,
              unitPrice: Number(editingPurchase.unitPrice) || 0,
            }
          : p
      );
      setPurchases(updated);
    }
    setMode('list');
    setEditingPurchase(null);
  };

  const handleFormCancel = () => {
    setMode('list');
    setEditingPurchase(null);
  };

  const handleExport = () => {
    alert('تنزيل البيانات وتصديرها سيتفعّل عند ربط النظام.\nحالياً الزر تجريبي فقط.');
  };

  return (
    <div className="chemicals-page">
      <div className="chemicals-header-row">
        <div>
          <h1 className="chemicals-title">سجل شراء الكيماويات</h1>
          <p className="chemicals-subtitle">
            متابعة كل عمليات الشراء والفواتير التي تخص الكيماويات والأسمدة.
          </p>
        </div>
        <button className="btn-outline" onClick={handleExport}>
          <span className="material-symbols-outlined">download</span>
          تنزيل البيانات
        </button>
      </div>

      {mode === 'form' && editingPurchase ? (
        <div className="chem-card chem-form-card">
          <h2 className="form-title">
            {editingPurchase.id == null ? 'تسجيل عملية شراء' : 'تعديل عملية شراء'}
          </h2>
          <form className="chem-form" onSubmit={handleFormSubmit}>
            <div className="form-row two-cols">
              <div>
                <label>اسم المادة</label>
                <input
                  type="text"
                  value={editingPurchase.name}
                  onChange={(e) => handleFormChange('name', e.target.value)}
                  required
                />
              </div>
              <div>
                <label>التاريخ</label>
                <input
                  type="date"
                  value={editingPurchase.date}
                  onChange={(e) => handleFormChange('date', e.target.value)}
                />
              </div>
            </div>
            <div className="form-row two-cols">
              <div>
                <label>الكمية</label>
                <input
                  type="text"
                  value={editingPurchase.quantity}
                  onChange={(e) => handleFormChange('quantity', e.target.value)}
                />
              </div>
              <div>
                <label>الوزن / الحجم</label>
                <input
                  type="text"
                  value={editingPurchase.weight}
                  onChange={(e) => handleFormChange('weight', e.target.value)}
                />
              </div>
            </div>
            <div className="form-row two-cols">
              <div>
                <label>سعر الكيلو / اللتر (ج.م)</label>
                <input
                  type="number"
                  value={editingPurchase.unitPrice}
                  onChange={(e) => handleFormChange('unitPrice', e.target.value)}
                  min="0"
                />
              </div>
              <div>
                <label>المورد</label>
                <input
                  type="text"
                  value={editingPurchase.supplier}
                  onChange={(e) => handleFormChange('supplier', e.target.value)}
                />
              </div>
            </div>
            <div className="form-actions">
              <button
                type="button"
                className="btn-secondary"
                onClick={handleFormCancel}
              >
                إلغاء
              </button>
              <button type="submit" className="btn-primary">
                حفظ
              </button>
            </div>
          </form>
        </div>
      ) : null}

      <div className="chemicals-stats-row">
        <div className="chem-card stat-card">
          <span className="stat-label">إجمالي المشتريات (الشهر الحالي)</span>
          <span className="stat-value">
            {totalAmount.toLocaleString('ar-EG')} ج.م
          </span>
          <span className="stat-note positive">+9% عن نفس الشهر الماضي</span>
        </div>
        <div className="chem-card stat-card">
          <span className="stat-label">الطلبات المعلقة</span>
          <span className="stat-value">18 طلب</span>
          <span className="stat-note">بما فيها أوامر التوريد المفتوحة</span>
        </div>
        <div className="chem-card stat-card">
          <span className="stat-label">مورّدين جدد</span>
          <span className="stat-value">4 مورّدين</span>
          <span className="stat-note">خلال آخر 30 يوم</span>
        </div>
      </div>

      <div className="chemicals-table-card chem-card">
        <div className="chemicals-table-header">
          {mode === 'list' && (
            <button className="btn-primary" onClick={handleAddPurchase}>
            <span className="material-symbols-outlined">add_chart</span>
            تسجيل عملية شراء
          </button>
          )}
          <div className="chem-table-actions">
            <button className="btn-chip">تصدير</button>
            <button className="btn-chip">
              <span className="material-symbols-outlined">filter_list</span>
              فلترة
            </button>
          </div>
        </div>

        <div className="chemicals-table-wrapper">
          <table className="chemicals-table">
            <thead>
              <tr>
                <th>التاريخ</th>
                <th>اسم المادة</th>
                <th>الكمية</th>
                <th>الوزن / الحجم</th>
                <th>سعر الكيلو / اللتر</th>
                <th>المورد</th>
                <th>الإجراءات</th>
              </tr>
            </thead>
            <tbody>
              {pagedPurchases.map((p) => (
                <tr key={p.id}>
                  <td>{new Date(p.date).toLocaleDateString('ar-EG')}</td>
                  <td>{p.name}</td>
                  <td>{p.quantity}</td>
                  <td>{p.weight}</td>
                  <td>{p.unitPrice.toLocaleString('ar-EG')} ج.م</td>
                  <td>{p.supplier}</td>
                  <td>
                    <div className="chem-row-actions">
                      <button
                        className="icon-btn danger"
                        onClick={() => handleDeletePurchase(p)}
                        title="حذف العملية"
                      >
                        <span className="material-symbols-outlined">delete</span>
                      </button>
                      <button
                        className="icon-btn"
                        onClick={() => handleEditPurchase(p)}
                        title="تعديل العملية"
                      >
                        <span className="material-symbols-outlined">edit</span>
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div className="chemicals-table-footer">
          <span className="footer-text">
            مُعرض: {pagedPurchases.length} من أصل {purchases.length} عملية (بيانات وهمية)
          </span>
          <div className="pagination">
            <button
              className={`page-btn ${currentPage === 1 ? 'disabled' : ''}`}
              onClick={() => currentPage > 1 && setCurrentPage(currentPage - 1)}
            >
              {'<'}
            </button>
            {Array.from({ length: totalPages }).map((_, index) => {
              const page = index + 1;
              return (
                <button
                  key={page}
                  className={`page-btn ${currentPage === page ? 'active' : ''}`}
                  onClick={() => setCurrentPage(page)}
                >
                  {page}
                </button>
              );
            })}
            <button
              className={`page-btn ${
                currentPage === totalPages ? 'disabled' : ''
              }`}
              onClick={() =>
                currentPage < totalPages && setCurrentPage(currentPage + 1)
              }
            >
              {'>'}
            </button>
          </div>
        </div>
      </div>

      <ConfirmDialog
        open={confirmState.open}
        title="تأكيد حذف عملية الشراء"
        message="هل أنت متأكد من حذف عملية الشراء هذه من سجل الكيماويات؟ البيانات الحالية تجريبية لأغراض العرض."
        confirmLabel="حذف"
        cancelLabel="إلغاء"
        onConfirm={handleConfirmDelete}
        onCancel={handleCancelDelete}
      />
    </div>
  );
}

export default Chemicals;
