import React, { useEffect, useRef, useState } from 'react';
import { Link } from 'react-router-dom';
import { Chart, registerables } from 'chart.js';
import './Overview.css';

Chart.register(...registerables);

function Overview() {
  const chartRef = useRef(null);
  const chartInstance = useRef(null);
  const [selectedFilter, setSelectedFilter] = useState('30days');

  useEffect(() => {
    let timer;
    const initChart = () => {
      if (chartRef.current) {
        if (chartInstance.current) {
          chartInstance.current.destroy();
        }

        const ctx = chartRef.current.getContext('2d');
        chartInstance.current = new Chart(ctx, {
          type: 'bar',
          data: {
            labels: ['يناير', 'فبراير', 'مارس', 'أبريل', 'مايو', 'يونيو'],
            datasets: [{
              label: 'الإيرادات',
              data: [45, 30, 65, 48, 80, 55],
              backgroundColor: (context) => {
                const index = context.dataIndex;
                return index === 4 ? '#8a9178' : '#e2e5dc';
              },
              borderRadius: 8,
              barThickness: 45,
            }]
          },
          options: {
            responsive: true,
            maintainAspectRatio: false,
            animation: {
              duration: 1000,
              easing: 'easeInOutQuart'
            },
            plugins: {
              legend: {
                display: false
              },
              tooltip: {
                backgroundColor: '#1a1f14',
                titleFont: { family: 'Cairo' },
                bodyFont: { family: 'Cairo' },
                rtl: true
              }
            },
            scales: {
              y: {
                beginAtZero: true,
                grid: {
                  display: true,
                  drawBorder: false,
                  color: '#f0f0f0'
                },
                ticks: {
                  display: false
                }
              },
              x: {
                grid: {
                  display: false
                },
                ticks: {
                  color: '#8a9178',
                  font: {
                    family: 'Cairo',
                    size: 12
                  }
                }
              }
            }
          }
        });
      }
    };

    // Small delay to ensure container height is detected properly
    timer = setTimeout(initChart, 200);

    return () => {
      clearTimeout(timer);
      if (chartInstance.current) {
        chartInstance.current.destroy();
      }
    };
  }, []);

  const stats = [
    { title: 'إجمالي الصرف', value: '45,000 ج.م', change: '+5%', status: 'up', icon: 'payments' },
    { title: 'إجمالي الإيرادات', value: '80,000 ج.م', change: '+12%', status: 'up', icon: 'trending_up' },
    { title: 'صافي المكسب', value: '35,000 ج.م', change: '8%', status: 'neutral', icon: 'savings' },
    { title: 'عدد العمال', value: '12', change: '+1', status: 'up', icon: 'groups' },
    { title: 'عمليات الرش (الشهر)', value: '8', change: '0%', status: 'neutral', icon: 'sprinkler' },
  ];

  const expenses = [
    { name: 'كيماويات وأسمدة', percentage: 45, color: '#485935' },
    { name: 'يوميات عمال', percentage: 30, color: '#8a9178' },
    { name: 'سولار وصيانة', percentage: 15, color: '#CADBB7' },
    { name: 'حاجات تانية', percentage: 10, color: '#e2e5dc' },
  ];

  const activities = [
    { title: 'دورة رش رقم #45', date: '12 يونيو 2024', user: 'كمال سالم', status: 'خلصت', cost: '1,200 ج.م', type: 'spray' },
    { title: 'شراء أسمدة نيتروجينية', date: '11 يونيو 2024', user: 'أحمد محمد', status: 'خلصت', cost: '5,850 ج.م', type: 'chemical' },
    { title: 'صيانة شبكة الري', date: '10 يونيو 2024', user: 'مؤسسة الواحة', status: 'شغالين فيها', cost: '2,400 ج.م', type: 'irrigation' },
    { title: 'دفع يوميات العمال - أسبوعي', date: '09 يونيو 2024', user: 'أحمد محمد', status: 'خلصت', cost: '8,500 ج.م', type: 'labor' },
  ];

  return (
    <div className="overview-page">
      <div className="page-header">
        <h1>نظرة عامة على المزرعة</h1>
      </div>
      <div className="stats-grid">
        {stats.map((stat, index) => (
          <div className="stat-card" key={index}>
            <div className="stat-header">
              <span className="stat-title">{stat.title}</span>
              <span className={`stat-change ${stat.status}`}>{stat.change}</span>
            </div>
            <div className="stat-body">
              <span className="stat-value">{stat.value}</span>
              <span className="stat-icon-bg"><span className="material-symbols-outlined">{stat.icon}</span></span>
            </div>
          </div>
        ))}
      </div>

      <div className="charts-row">
        <div className="chart-container-main glass-card">
          <div className="chart-header">
            <h3>الإيرادات الشهرية</h3>
            <span className="chart-subtitle">تطور الدخل آخر 6 شهور</span>
          </div>
          <div className="chart-wrapper">
            <canvas ref={chartRef}></canvas>
          </div>
        </div>

        <div className="expenses-breakdown glass-card">
          <h3>تقسيمة المصاريف</h3>
          <div className="expense-list">
            {expenses.map((expense, index) => (
              <div className="expense-item" key={index}>
                <div className="expense-info">
                  <span className="expense-name">{expense.name}</span>
                  <span className="expense-percentage">%{expense.percentage}</span>
                </div>
                <div className="progress-bar">
                  <div
                    className="progress-fill"
                    style={{ width: `${expense.percentage}%`, backgroundColor: expense.color }}
                  ></div>
                </div>
              </div>
            ))}
          </div>
          <Link to="/dashboard/reports" className="report-btn">افتح التقرير بالتفصيل</Link>
        </div>
      </div>

      <div className="activities-section glass-card">
        <div className="section-header">
          <h3>آخر اللي حصل</h3>
          <div className="header-actions">
            <div className="filter-group">
              <select
                className="filter-select"
                value={selectedFilter}
                onChange={(e) => setSelectedFilter(e.target.value)}
              >
                <option value="today">كل الايام</option>
                <option value="7days">7 أيام</option>
                <option value="14days">15 يوم</option>
                <option value="30days">30 يوم</option>
              </select>
            </div>
            <Link to="/dashboard/reports" className="view-all">شوف الكل</Link>
          </div>
        </div>
        <table className="activities-table">
          <thead>
            <tr>
              <th>العملية</th>
              <th>التاريخ</th>
              <th>اللي عملها</th>
              <th>الحالة</th>
              <th>التكلفة</th>
            </tr>
          </thead>
          <tbody>
            {activities.map((activity, index) => (
              <tr key={index}>
                <td className="activity-cell">
                  <span className={`activity-icon icon-${activity.type}`}>
                    <span className="material-symbols-outlined">
                      {activity.type === 'spray' ? 'event_available' :
                        activity.type === 'chemical' ? 'biotech' :
                          activity.type === 'irrigation' ? 'water_drop' : 'groups'}
                    </span>
                  </span>
                  {activity.title}
                </td>
                <td>{activity.date}</td>
                <td>{activity.user}</td>
                <td>
                  <span className={`status-badge ${activity.status === 'خلصت' ? 'completed' : 'pending'}`}>
                    {activity.status}
                  </span>
                </td>
                <td className="cost-cell">{activity.cost}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default Overview;
